import {ORDER_HISTORY_STORAGE_KEY,ORDER_STORAGE_KEY,SETTINGS_STORAGE_KEY,DRAFT_STORAGE_KEY,DINE_STORAGE_KEY,TERMINAL_ID_STORAGE_KEY,OPERATIONS_STORAGE_KEY,PRINTER_STORAGE_KEY,BACKUP_STORAGE_KEY,readJSON,writeJSON} from '../../shared/store.js';
import {clearDraftsForDayClose} from '../../shared/operations.js';
import {escapeHtml,showToast} from '../../shared/components.js';
import {businessWindow,buildReportRange,buildOperationalReport,CASH_DENOMINATIONS,syncCashDenomination,totalCashBreakdown,defaultCashDistribution,buildOpeningCashState,calculateDayCloseReconciliation,createDayClose,buildCsvExport,createBackupEnvelope,validateBackupEnvelope,restoreBackupValues,buildDiagnosticReport} from './more-domain.js';
import {defaultPrinterState,validatePrinter,diagnosePrinterConfiguration,renderPrintDocument,createPrintJobs,retryPrintJob,reroutePrintJob,buildAndroidPrintPayload,importExternalPrintJobs} from './print-domain.js';
import {normalizeCategoryLayout} from '../order/category-layout.js';
import {renderGlobalStatusBar,renderBottomNav} from '../../shared/shell.js';
import {activeDineOrderIdentities,latestOrderDisplayNumber,orderDisplayNumber} from '../../shared/order-identity.js';

const app=document.getElementById('app'),VERSION='order-v1-31';
const terminalId=localStorage.getItem(TERMINAL_ID_STORAGE_KEY)||'SMT-01';
let orders=readJSON(ORDER_HISTORY_STORAGE_KEY,[]),orderState=readJSON(ORDER_STORAGE_KEY,{}),settings=readJSON(SETTINGS_STORAGE_KEY,{});
let operations={dayCloseDraft:null,dayCloses:[],openingCashAdjustments:[],expenses:[],audit:[],outbox:[],updateChecks:[],...readJSON(OPERATIONS_STORAGE_KEY,{})};
let printerState={...defaultPrinterState(),...readJSON(PRINTER_STORAGE_KEY,{})};
printerState=importExternalPrintJobs(printerState,{orders,dine:readJSON(DINE_STORAGE_KEY,null)});
let backupState={items:[],latestEnvelope:null,imported:null,...readJSON(BACKUP_STORAGE_KEY,{})},importedBackup=backupState.imported||null;
const initialReportRange=buildReportRange('today');
let detailId='',confirmId='',reportTab='營業',reportPreset='today',reportRange=initialReportRange,reportCustomStart=initialReportRange.startDate,reportCustomEnd=initialReportRange.endDate,reportProductView='products',reportDrilldown=null,printerView='devices',editingPrinterId='',previewTemplateId='',rerouteJobId='',systemView='summary',restoreScope='all';
let currentBusinessDate=businessWindow().id;
const displaySettings={quickMode:Boolean(settings.morePage?.quickMode??orderState.quickMode),productImages:settings.morePage?.productImages!==false&&settings.catalog?.showImages!==false,sounds:settings.morePage?.sounds!==false,theme:settings.morePage?.theme||'warm',categoryLayout:normalizeCategoryLayout(settings.categoryLayout)};

function saveOperations(){writeJSON(OPERATIONS_STORAGE_KEY,operations)}
function savePrinters(){printerState.updatedAt=Date.now();writeJSON(PRINTER_STORAGE_KEY,printerState)}
function saveBackups(){writeJSON(BACKUP_STORAGE_KEY,backupState)}
savePrinters();
function money(value){return '$'+Number(value||0).toLocaleString('zh-HK',{minimumFractionDigits:0,maximumFractionDigits:2})}
function dateTime(value){return value?new Date(value).toLocaleString('zh-HK',{month:'2-digit',day:'2-digit',hour:'2-digit',minute:'2-digit'}):'未有紀錄'}
function report(){return buildOperationalReport(orders)}
function analyticsReport(){return buildOperationalReport(orders,{range:reportRange})}
function navigate(route){window.MoreFunPageBridge?.navigate(route)}
function themeName(id){return ({warm:'暖米',tea:'焙茶',sprout:'青芽',purple:'紫米',sunset:'夕照',mist:'霧藍'})[id]||'暖米'}
function tag(text,tone=''){return `<b class="status-tag ${tone}">${escapeHtml(text)}</b>`}
function metric(label,value,sub=''){return `<div class="metric"><span>${escapeHtml(label)}</span><strong>${escapeHtml(value)}</strong>${sub?`<small>${escapeHtml(sub)}</small>`:''}</div>`}
function panel(title,body){return `<section class="info-panel"><h3>${escapeHtml(title)}</h3>${body}</section>`}
function note(copy,tone=''){return `<div class="notice ${tone}">${copy}</div>`}
function row(label,detail='',right=''){return `<div class="row"><span><strong>${escapeHtml(label)}</strong>${detail?`<small>${escapeHtml(detail)}</small>`:''}</span>${right}</div>`}
function toggle(key){return `<button class="toggle ${displaySettings[key]?'on':''}" data-action="toggle-setting" data-value="${key}" aria-pressed="${displaySettings[key]?'true':'false'}"><i></i></button>`}
function audit(type,detail={}){if(type==='backup.restored')operations={dayCloseDraft:null,dayCloses:[],expenses:[],audit:[],outbox:[],updateChecks:[],...readJSON(OPERATIONS_STORAGE_KEY,{})};operations.audit=[...(operations.audit||[]),{type,detail,terminalId,at:Date.now()}];saveOperations()}

function printerHealth(){const enabled=printerState.printers.filter(x=>x.enabled),ready=enabled.filter(x=>validatePrinter(x).ok).length,failed=printerState.jobs.filter(x=>x.status==='failed').length,blocked=printerState.jobs.filter(x=>x.status==='blocked').length;return {enabled:enabled.length,ready,failed,blocked}}
function cards(){const r=report(),closed=(operations.dayCloses||[]).filter(x=>x.businessDate===r.businessWindow.id).at(-1),health=printerHealth(),latest=backupState.items.at(-1);return [
  {id:'dayclose',icon:'＄',title:'收銀與日結',desc:'營業摘要、現金核對、支出、差異與版本化日結',tag:closed?`已日結 V${closed.version}`:'今日未日結',tone:closed?'ok':'warn',meta:`現金應有 ${money(r.summary.cashExpected)}`},
  {id:'reports',icon:'▥',title:'報表與分析',desc:'營運、渠道、商品、付款異常及資料匯出',tag:`淨銷售 ${money(r.summary.netSales)}`,tone:'ok',meta:`付款待核實 ${r.summary.pendingPayments} 張`},
  {id:'printers',icon:'▧',title:'打印與設備',desc:'五部打印機、網絡設定、格式、診斷、重試及改送',tag:`已設定 ${health.ready}/${health.enabled}`,tone:health.failed||health.blocked?'warn':health.ready===health.enabled?'ok':'warn',meta:`阻塞 ${health.blocked}｜失敗 ${health.failed}`},
  {id:'backup',icon:'⇩',title:'備份與恢復',desc:'本機快照、下載、校驗、匯入與安全恢復',tag:latest?'最近備份已驗證':'尚未建立備份',tone:latest?'ok':'warn',meta:latest?dateTime(latest.createdAt):'可立即建立'},
  {id:'display',icon:'◐',title:'顯示與操作',desc:'快速模式、六套主題、產品圖片與操作聲音',tag:displaySettings.quickMode?'快速模式':'一般模式',tone:'ok',meta:`${themeName(displaySettings.theme)}主題／聲音${displaySettings.sounds?'開啟':'關閉'}`},
  {id:'system',icon:'⚙',title:'系統與更新',desc:'版本、同步工作、裝置能力、診斷及操作紀錄',tag:`待同步 ${(operations.outbox||[]).filter(x=>!['sent','completed'].includes(x.status)).length}`,tone:'warn',meta:`${VERSION}｜打印工作 ${printerState.jobs.length}`}
]}
function analysisBars(items){const rows=(items||[]).slice(0,4),max=Math.max(1,...rows.map(item=>Number(item.amount||0)));return rows.length?rows.map(item=>`<div class="analysis-bar"><span>${escapeHtml(item.name)}<small>${item.orders||0} 張</small></span><i><b style="width:${Math.max(4,Number(item.amount||0)/max*100)}%"></b></i><strong>${money(item.amount)}</strong></div>`).join(''):'<p>今日尚未有資料</p>'}
function analysisSnapshot(){const r=report();return `<section class="more-analysis"><div class="analysis-total"><small>今日營業</small><strong>${money(r.summary.netSales)}</strong><span>${r.summary.completedOrders} 張完成單｜${r.summary.itemUnits} 件產品</span></div><div><h2>渠道分拆</h2>${analysisBars(r.channels)}</div><div><h2>付款分拆</h2>${analysisBars(r.payments)}</div><button data-action="open-detail" data-value="reports">完整分析 ›</button></section>`}
function topbar(){return renderGlobalStatusBar({terminalId,operationLabel:'本機可營運',lastOrder:latestOrderDisplayNumber([...orders,...activeDineOrderIdentities(readJSON(DINE_STORAGE_KEY,null))]),rightActions:`<button class="top-btn" data-action="navigate" data-value="orders">待核實 <span class="badge">${report().summary.pendingPayments}</span></button><button class="top-btn" data-action="navigate" data-value="soldout">售罄</button><button class="top-btn" data-action="open-detail" data-value="display">快捷 <span class="mini-switch ${displaySettings.quickMode?'on':''}"></span></button><button class="top-btn ${printerHealth().failed||printerHealth().blocked?'alert':''}" data-action="open-detail" data-value="printers">設備</button><button class="top-btn" data-action="open-detail" data-value="system">更多操作</button>`})}
function bottomNav(){return renderBottomNav('more',{badges:{orders:report().summary.pendingPayments}})}
function mainPage(){const x=businessWindow();return `<main class="app">${topbar()}<section class="workspace more-workspace"><header class="more-heading"><div><h1>更多</h1><p>六個入口已連接本機正式資料；外部橋接狀態會分開顯示。</p></div><span>營業日：${x.id}　05:00–翌日04:59</span></header>${analysisSnapshot()}<section class="more-grid">${cards().map(c=>`<button class="more-card" data-action="open-detail" data-value="${c.id}"><span class="more-icon">${c.icon}</span><span class="more-copy"><strong>${c.title}</strong><small>${c.desc}</small><span class="card-status">${tag(c.tag,c.tone)}<em>${c.meta}</em></span></span><i>›</i></button>`).join('')}</section></section>${bottomNav()}</main>`}

function previousRetainedCash(businessDate){return [...(operations.dayCloses||[])].filter(x=>x.businessDate!==businessDate).sort((a,b)=>Number(b.createdAt)-Number(a.createdAt))[0]?.cashRetained||0}
function openingCashState(){return buildOpeningCashState(operations.dayCloses,operations.openingCashAdjustments,report().businessWindow.id)}
function cashExpenseTotal(expenses){return (expenses||[]).filter(x=>(x.paymentMethod||'現金')==='現金').reduce((sum,x)=>sum+Number(x.amount||0),0)}
function dayCloseModel(){const r=report(),opening=openingCashState(),draft=operations.dayCloseDraft||{},expenses=draft.expenses||operations.expenses||[],breakdown=draft.cashBreakdown||{},counted=totalCashBreakdown(breakdown),openingFloat=Number(draft.openingFloat??opening.openingCash),cashExpenses=cashExpenseTotal(expenses),reconciliation=calculateDayCloseReconciliation({report:r,cashCounted:counted,openingFloat,cashExpenses}),threshold=Number(r.summary.netSales||0)*.03,reviewRequired=Math.abs(reconciliation.cashDifference)>threshold,defaults=defaultCashDistribution(counted,openingFloat),retained=Number(draft.cashRetained??defaults.cashRetained),withdrawn=Number(draft.cashWithdrawn??defaults.cashWithdrawn),nextVersion=(operations.dayCloses||[]).filter(x=>x.businessDate===r.businessWindow.id).reduce((n,x)=>Math.max(n,Number(x.version||0)),0)+1;return {r,opening,draft,expenses,breakdown,counted,openingFloat,cashExpenses,reconciliation,threshold,reviewRequired,retained,withdrawn,nextVersion}}
function cashRows(kind,breakdown){return CASH_DENOMINATIONS.filter(row=>row.kind===kind).map(row=>{const value=breakdown[row.id]||{quantity:0,amount:0};return `<div class="cash-count-row"><strong>${row.label}</strong><label><span>${kind==='note'?'張數':'枚數'}</span><input type="number" min="0" step="1" inputmode="numeric" data-action="denomination-quantity" data-denomination="${row.id}" value="${value.quantity||''}"></label><label><span>金額</span><input type="number" min="0" step="${row.value}" inputmode="decimal" data-action="denomination-amount" data-denomination="${row.id}" value="${value.amount||''}"></label></div>`}).join('')}
function dayCloseContent(){const m=dayCloseModel(),r=m.r,draft=m.draft,x=m.reconciliation,distributionOk=Math.abs(m.withdrawn+m.retained-m.counted)<.001;return `${note('先確認上次留底及今日開機調整，再按紙幣／硬幣點算櫃桶；待核實電話、WhatsApp 及磨飯 App 訂單會由實點現金反推。')}${panel('今日開機現金',`<div class="form-grid three"><label>上次留底<input type="number" data-field="previous-retained" value="${m.opening.previousRetained}" disabled></label><label>今日加減調整<input type="number" step="0.1" data-field="opening-adjustment" value="${m.opening.adjustment}"></label><label>開工現金<input type="number" data-field="opening-cash" value="${m.opening.openingCash}" readonly></label></div><div class="button-row"><button data-action="confirm-opening-cash">${m.opening.confirmed?'更新開工現金':'確認開工現金'}</button>${tag(m.opening.confirmed?'已確認':'尚未確認',m.opening.confirmed?'ok':'warn')}</div>`)}<div class="metrics">${metric('淨銷售',money(r.summary.netSales))}${metric('櫃桶實點',money(m.counted),'由面額自動合計')}${metric('待核實款項',money(r.summary.unverifiedDirectTotal),`${r.summary.unverifiedDirectOrders} 張待反推`)}${metric('目前差額',money(x.cashDifference),`門檻 ${money(m.threshold)}`)}</div><div class="dayclose-layout"><section class="info-panel cash-count-panel"><header><div><h3>紙幣及硬幣盤點</h3><small>只列店舖接受面額；輸入數量或金額會即時互推</small></div><strong data-live="cash-counted">${money(m.counted)}</strong></header><input type="hidden" data-field="cash-counted" value="${m.counted}"><div class="cash-count-columns"><section><h4>紙幣</h4><div class="cash-count-grid">${cashRows('note',m.breakdown)}</div></section><section><h4>硬幣</h4><div class="cash-count-grid">${cashRows('coin',m.breakdown)}</div></section></div></section><div class="dayclose-side">${panel('櫃桶現金安排',`<div class="form-grid three"><label>開工底金<input type="number" min="0" step="0.1" data-field="opening-float" value="${m.openingFloat}"></label><label>收工提取<input type="number" min="0" step="0.1" data-field="cash-withdrawn" value="${m.withdrawn}"></label><label>留底現金<input type="number" min="0" step="0.1" data-field="cash-retained" value="${m.retained}"></label></div>${row('分配核對',`${money(m.withdrawn)} 提取＋${money(m.retained)} 留底`,tag(distributionOk?'已完整分配':'未等於實點現金',distributionOk?'ok':'bad'))}`)}${panel('付款方式反推',`${row('已知櫃桶應有',money(x.knownDrawerExpected),'開工底金＋已核實現金－支出')}${row('待核實現金',money(x.inferredUnverifiedCash),tag('反推'))}${row('待核實非現金',money(x.inferredUnverifiedNonCash),tag('反推'))}${row('已確認電子／平台',money(r.summary.electronicExpected+r.summary.platformGross))}`)}${panel('現金支出',`<div class="form-grid"><label>支出分類<select data-field="expense-category"><option>食材</option><option>零用</option><option>運輸</option><option>其他</option></select></label><label>支出金額<input type="number" min="0" step="0.1" data-field="expense-amount"></label><label class="wide-field">支出備註<input data-field="expense-note" placeholder="例如：補貨"></label></div><button data-action="add-expense">加入支出</button><div class="compact-list">${m.expenses.map((item,index)=>`<div><span>${escapeHtml(item.category)}｜${money(item.amount)}<small>${escapeHtml(item.note||'沒有備註')}</small></span><button data-action="remove-expense" data-index="${index}">刪除</button></div>`).join('')||'<p>未有支出</p>'}</div>`)}${panel('差額覆核與版本',`${row('實點差額',money(x.cashDifference),tag(m.reviewRequired?'超出當日淨銷售 3%':'3% 門檻內',m.reviewRequired?'bad':'ok'))}<label class="full-label">差額原因<textarea data-field="difference-reason" placeholder="超出 3% 必填">${escapeHtml(draft.reason||'')}</textarea></label>${m.reviewRequired?`<button class="approval-toggle ${draft.approvedOverride?'approved':''}" data-action="toggle-dayclose-approval"><span>${draft.approvedOverride?'✓':'!'}</span><b>${draft.approvedOverride?'已由本終端授權通過':'需要有權人確認通過'}</b><small>${draft.approvedOverride?terminalId+'｜會寫入稽核紀錄':'填寫原因後再按此授權'}</small></button>`:note('差額在門檻內，不需要額外授權。','small')}${row('下一日結版本',`V${m.nextVersion}`)}${row('已保存草稿',dateTime(draft.savedAt))}`)}</div></div>`}
const reportPresets=[['today','今日'],['yesterday','昨日'],['7d','最近 7 日'],['30d','最近 30 日'],['3m','最近 3 個月'],['6m','最近 6 個月'],['custom','自訂日期']];
function reportRangeControls(){
  return `<section class="report-range"><div class="report-range-buttons">${reportPresets.map(([value,label])=>`<button data-action="report-range" data-value="${value}" class="${reportPreset===value?'active':''}">${label}</button>`).join('')}</div><div class="report-range-current"><span>目前範圍<strong>${escapeHtml(reportRange.label)}</strong></span>${reportPreset==='custom'?`<label>開始日期<input type="date" data-report-start value="${reportCustomStart}"></label><label>結束日期<input type="date" data-report-end value="${reportCustomEnd}"></label><button data-action="apply-custom-range">套用日期</button>`:''}</div></section>`;
}
function breakdownTable(items,kind){
  return `<div class="report-table report-breakdown"><header><span>項目</span><span>單數</span><span>原額</span><span>折扣</span><span>應收</span><span>實收</span><span>退款</span><span>差額</span><span>對數狀態</span></header>${items.map((item,index)=>`<button data-action="report-drilldown" data-kind="${kind}" data-index="${index}"><span><strong>${escapeHtml(item.name)}</strong><small>平均 ${money(item.averageOrderValue)}</small></span><b>${item.orders}</b><b>${money(item.gross)}</b><b>${money(item.discounts)}</b><b>${money(item.expected)}</b><b>${money(item.received)}</b><b>${money(item.refunds)}</b><b class="${item.difference?'bad':''}">${money(item.difference)}</b><em class="${item.pending||item.difference?'warn':'ok'}">${escapeHtml(item.status)}</em></button>`).join('')||'<p>此日期範圍未有資料</p>'}</div>`;
}
function rankingTable(items,kind){
  return `<div class="report-table ranking-table"><header><span>項目</span><span>售出數量</span><span>銷售額</span><span>佔比</span><span>訂單</span></header>${items.map((item,index)=>`<button data-action="report-drilldown" data-kind="${kind}" data-index="${index}"><span><strong>${escapeHtml(item.name)}</strong>${item.category?`<small>${escapeHtml(item.category)}</small>`:''}</span><b>${item.quantity||0}</b><b>${money(item.amount)}</b><b>${Number(item.share||0).toFixed(1)}%</b><em>查看 ${item.orders||0} 張 ›</em></button>`).join('')||'<p>此日期範圍未有商品資料</p>'}</div>`;
}
function anomalyTable(items){
  return `<div class="report-table anomaly-table"><header><span>異常類型</span><span>次數</span><span>涉及金額</span><span>訂單</span></header>${items.map((item,index)=>`<button data-action="report-drilldown" data-kind="anomalies" data-index="${index}"><span><strong>${escapeHtml(item.name)}</strong></span><b>${item.count}</b><b>${money(item.amount)}</b><em>查看訂單 ›</em></button>`).join('')||'<p>此日期範圍未有異常紀錄</p>'}</div>`;
}
function reportItems(kind,r){return kind==='channels'?r.channels:kind==='payments'?r.payments:kind==='products'?r.products:kind==='categories'?r.categories:kind==='hours'?r.hours:kind==='anomalies'?r.anomalies:[]}
function reportDrilldownPanel(r){
  if(!reportDrilldown)return '';
  const items=reportItems(reportDrilldown.kind,r),group=items[reportDrilldown.index];
  if(!group)return '';
  const selected=new Set(group.orderIds||[]),rows=r.orders.filter(order=>selected.has(order.id)).sort((a,b)=>Number(b.completedAt||b.checkedOutAt||b.acceptedAt)-Number(a.completedAt||a.checkedOutAt||a.acceptedAt));
  return `<section class="report-drilldown"><header><div><small>對應訂單</small><h3>${escapeHtml(group.name)}｜${rows.length} 張</h3></div><button data-action="close-report-drilldown">關閉</button></header><div>${rows.map(order=>`<article><strong>${escapeHtml(orderDisplayNumber(order))}</strong><span>${dateTime(order.completedAt||order.checkedOutAt||order.acceptedAt)}</span><span>${escapeHtml(order.source||'未分類')}</span><span>${escapeHtml(order.paymentMethod||'未分類')}</span><b>${money(Math.max(0,Number(order.amount||0)-Number(order.refundedAmount||order.refundAmount||0)))}</b><em>${escapeHtml(order.paymentStatus||order.status||'未分類')}</em></article>`).join('')||'<p>未有對應訂單</p>'}</div></section>`;
}
function dayCloseHistory(){
  const rows=(operations.dayCloses||[]).filter(item=>item.businessDate>=reportRange.startDate&&item.businessDate<=reportRange.endDate).sort((a,b)=>Number(b.createdAt)-Number(a.createdAt)).slice(0,12);
  return `<div class="data-table">${rows.map(item=>`<div><span><strong>${escapeHtml(item.businessDate)}｜V${item.version}</strong><small>${escapeHtml(item.terminalId||'未有終端')}｜${dateTime(item.createdAt)}</small></span><b>${money(item.report?.summary?.netSales||0)}</b></div>`).join('')||'<p>此日期範圍未有日結紀錄</p>'}</div>`;
}
function reportsContent(){
  const r=analyticsReport(),tabs=['營業','渠道','付款','商品','異常'];
  let body='';
  if(reportTab==='營業')body=`<div class="metrics report-metrics">${metric('淨實收',money(r.summary.netSales))}${metric('銷售原額',money(r.summary.grossSales))}${metric('有效訂單',String(r.summary.completedOrders))}${metric('平均客單價',money(r.summary.averageOrderValue))}${metric('折扣總額',money(r.summary.discounts))}${metric('退款',`${money(r.summary.refunds)}｜${r.summary.refundOrders} 張`)}${metric('未結帳',`${money(r.summary.outstandingAmount)}｜${r.summary.outstandingOrders} 張`)}</div><div class="two-columns report-columns">${panel('每小時營業趨勢',breakdownTable(r.hours,'hours'))}${panel('日結紀錄',dayCloseHistory())}</div>`;
  if(reportTab==='渠道')body=panel('渠道分析｜點入每項查看對應訂單',breakdownTable(r.channels,'channels'));
  if(reportTab==='付款')body=`${note('訂單來源同付款方式已分開；付款對數會逐項顯示應收、實收、退款、差額及狀態。')}${panel('付款對數',breakdownTable(r.payments,'payments'))}`;
  if(reportTab==='商品'){
    const items=reportProductView==='products'?r.products:r.categories,kind=reportProductView;
    body=`<div class="report-subtabs"><button data-action="report-product-view" data-value="products" class="${kind==='products'?'active':''}">產品排行</button><button data-action="report-product-view" data-value="categories" class="${kind==='categories'?'active':''}">分類排行</button></div>${panel(kind==='products'?'產品排行':'分類排行',rankingTable(items,kind))}`;
  }
  if(reportTab==='異常')body=panel('異常操作及營運例外',anomalyTable(r.anomalies));
  return `${reportRangeControls()}<div class="tabs report-tabs">${tabs.map(value=>`<button data-action="report-tab" data-value="${value}" class="${reportTab===value?'active':''}">${value}</button>`).join('')}</div>${body}${reportDrilldownPanel(r)}`;
}

const purposeNames={receipt:'顧客小票',production:'製作單',packing:'打包單',label:'標籤','label-backup':'標籤後備'};
function printerStatus(p){const check=validatePrinter(p);if(!p.enabled)return tag('已停用');if(!check.ok)return tag('設定未完成','warn');if(printerState.bridge.status!=='connected')return tag('設定完成｜待安卓橋接','warn');return tag('橋接可用','ok')}
function printerEditor(){const p=printerState.printers.find(x=>x.id===editingPrinterId);if(!p)return '';const primary=(p.purposes||[]).find(x=>['receipt','production','packing','label'].includes(x))||'label',templates=printerState.templates.filter(x=>x.documentType===primary&&x.status==='published');return `<section class="sub-editor"><header><div><small>${p.model}</small><h3>設定 ${escapeHtml(p.name)}</h3></div><button data-action="cancel-printer-edit">×</button></header><div class="form-grid three"><label>設備名稱<input data-field="printer-name" value="${escapeHtml(p.name)}"></label><label>用途<select data-field="printer-purpose">${Object.entries(purposeNames).map(([value,name])=>`<option value="${value}" ${p.purposes.includes(value)?'selected':''}>${name}</option>`).join('')}</select></label><label>連接方式<input value="${p.transport==='network'?'網絡 TCP／IP':'商米內置橋接'}" disabled></label>${p.transport==='network'?`<label>網絡地址<input data-field="printer-host" inputmode="decimal" placeholder="192.168.1.201" value="${escapeHtml(p.host)}"></label><label>連接埠<input data-field="printer-port" type="number" value="${p.port}"></label>`:'<input type="hidden" data-field="printer-host" value=""><input type="hidden" data-field="printer-port" value="0">'}<label>紙寬<select data-field="printer-paper">${[50,58,80].map(x=>`<option ${p.paperWidth===x?'selected':''}>${x}</option>`).join('')}</select></label><label>打印份數<input data-field="printer-copies" type="number" min="1" max="5" value="${p.copies}"></label><label>逾時毫秒<input data-field="printer-timeout" type="number" min="1000" max="30000" value="${p.timeoutMs}"></label><label>使用格式<select data-field="printer-template">${templates.map(x=>`<option value="${x.id}" ${p.templateAssignments?.[primary]===x.id?'selected':''}>${escapeHtml(x.name)}</option>`).join('')}</select></label></div><footer><button data-action="cancel-printer-edit">取消</button><button data-action="queue-test-print" data-id="${p.id}">建立測試工作</button><button class="primary" data-action="save-printer" data-id="${p.id}">儲存設備設定</button></footer></section>`}
function deviceList(){return `<div class="printer-list">${printerState.printers.map(p=>`<div><span><strong>${escapeHtml(p.name)}</strong><small>${p.model}｜${(p.purposes||[]).map(x=>purposeNames[x]||x).join('、')}｜${p.transport==='network'?(p.host||'未填網絡地址')+':'+p.port:'內置打印機'}</small></span><em>${p.lastDiagnostic?`${dateTime(p.lastDiagnostic.checkedAt)}｜${p.lastDiagnostic.nextStep}`:Object.values(p.templateAssignments||{}).join('')}</em>${printerStatus(p)}<span style="display:flex;gap:6px"><button style="min-height:42px;border:1px solid var(--line);border-radius:9px;background:#fff;font-weight:900" data-action="run-printer-diagnostic" data-id="${p.id}">診斷</button><button style="min-height:42px;border:1px solid var(--line);border-radius:9px;background:#fff;font-weight:900" data-action="edit-printer" data-id="${p.id}">設定</button></span></div>`).join('')}</div>${printerEditor()}`}
function sampleOrder(){return {id:'DEMO-001',source:'現場外賣',paymentMethod:'現金',amount:149,acceptedAt:Date.now(),items:[{name:'鹽酥雞',category:'小食',qty:3,unitPrice:18,options:{醬汁:'蜜糖芥末'}},{name:'手打檸檬茶',category:'飲品',qty:2,unitPrice:20,options:{冰量:'少冰'}},{name:'台式奶茶',category:'飲品',qty:1,unitPrice:16},{name:'菜飯便當',category:'便當',qty:1,unitPrice:45},{name:'F4 飯團',category:'飯團',qty:1,unitPrice:41}]}}
function printPreview(){const t=printerState.templates.find(x=>x.id===previewTemplateId);if(!t)return '';const doc=renderPrintDocument(t,sampleOrder());return `<section class="print-preview"><header><strong>${escapeHtml(t.name)}</strong><button data-action="close-template-preview">×</button></header><pre>${escapeHtml(doc.text)}</pre></section>`}
function templateList(){return `<div class="template-list">${printerState.templates.map(t=>`<article><span><small>管理端發佈｜版本 ${t.sourceVersion}</small><strong>${escapeHtml(t.name)}</strong><em>${t.paperWidth} 毫米｜SMT 只可選用</em></span><button data-action="preview-template" data-id="${t.id}">預覽</button></article>`).join('')}</div>${previewTemplateId?printPreview():''}`}
function jobList(){const jobs=[...printerState.jobs].sort((a,b)=>Number(b.createdAt)-Number(a.createdAt));return `<div class="job-list">${jobs.map(j=>{const p=printerState.printers.find(x=>x.id===j.printerId),compatible=x=>x.purposes?.includes(j.documentType)||(j.documentType==='label'&&x.purposes?.includes('label-backup'));return `<article><span><small>${escapeHtml(j.orderId||j.sourceRef?.orderId||'測試')}｜${dateTime(j.createdAt)}</small><strong>${escapeHtml(j.documentName||j.document||j.documentType)}</strong><em>${escapeHtml(p?.name||'未有目的地')}｜嘗試 ${j.attempts||0}｜${j.status==='queued'?'已排隊，待實體橋接':j.status==='blocked'?'設定阻塞':j.status==='failed'?'失敗':'已完成'}</em></span>${tag(j.status,j.status==='failed'?'bad':j.status==='blocked'?'warn':j.status==='printed'?'ok':'')}<button data-action="retry-print-job" data-id="${j.id}">重試</button><button data-action="build-bridge-payload" data-id="${j.id}">橋接資料</button><button data-action="reroute-print-job" data-id="${j.id}">改送</button>${rerouteJobId===j.id?`<div class="reroute-row">${printerState.printers.filter(x=>x.id!==j.printerId&&x.enabled&&compatible(x)).map(x=>`<button data-action="reroute-print-job" data-id="${j.id}" data-value="${x.id}">${escapeHtml(x.name)}</button>`).join('')||'<small>未有同用途後備打印機</small>'}</div>`:''}</article>`}).join('')||'<p>未有打印工作</p>'}</div>`}
function printersContent(){let body=deviceList();if(printerView==='templates')body=templateList();if(printerView==='jobs')body=jobList();return `${note('設定、格式、工作佇列及安卓橋接封包今輪可用；實體出紙要封裝 APK 後由設備回傳結果。')}<div class="tabs"><button class="${printerView==='devices'?'active':''}" data-action="printer-view" data-value="devices">五部設備</button><button class="${printerView==='templates'?'active':''}" data-action="printer-view" data-value="templates">打印格式</button><button class="${printerView==='jobs'?'active':''}" data-action="open-print-jobs" data-value="jobs">打印工作／重試</button></div>${body}`}

function backupContent(){const latest=backupState.items.at(-1),check=importedBackup?validateBackupEnvelope(importedBackup):null;return `${note('恢復前自動備份目前資料；匯入檔必須通過 Manifest、版本及 Checksum 校驗。')}<div class="metrics">${metric('最近完整備份',dateTime(latest?.createdAt))}${metric('已驗證備份',String(backupState.items.filter(x=>x.valid).length))}${metric('匯入檔案',importedBackup?(check.ok?'校驗通過':'校驗失敗'):'尚未選擇')}${metric('保留策略','7／4／6','每日／每週／每月')}</div><div class="two-columns">${panel('建立與下載',`${row('本機安全快照','只收集 morefun: SMT 資料')}${row('校驗方式','Manifest／Schema／FNV-1a Checksum')}${row('最近校驗值',latest?.checksum||'未有')}<div class="button-row"><button data-action="create-backup">建立安全快照</button><button data-action="download-backup" ${backupState.latestEnvelope?'':'disabled'}>下載 JSON／USB</button></div>`)}${panel('匯入與恢復',`<label class="file-picker">選擇備份檔案<input type="file" accept="application/json,.json" data-action="import-backup"></label>${check?row('校驗結果',check.ok?'通過，可選恢復範圍':check.errors.join('；'),tag(check.ok?'有效':'拒絕',check.ok?'ok':'bad')):''}<div class="button-row"><button data-action="restore-scope" data-value="settings" ${check?.ok?'':'disabled'}>只恢復設定／打印</button><button class="ghost-danger" data-action="restore-scope" data-value="all" ${check?.ok?'':'disabled'}>完整資料恢復</button></div>`)} </div>`}
function displayContent(){const c=displaySettings.categoryLayout;return `<div class="two-columns display-columns">${panel('操作模式',`${row('快速模式','套用到點單頁',toggle('quickMode'))}${row('產品及購物車圖片','套用到產品卡與購物車',toggle('productImages'))}${row('操作聲音','新單、錯誤及三十五分鐘提示',toggle('sounds'))}${row('工作區比例','沿用目前 30／70 鎖定比例',tag('30／70'))}`)}${panel('產品分類欄',`<div class="setting-choice"><strong>每行格數</strong><div class="segmented"><button data-action="category-columns" data-value="5" class="${c.columns===5?'active':''}">5個</button><button data-action="category-columns" data-value="6" class="${c.columns===6?'active':''}">6個</button><button data-action="category-columns" data-value="7" class="${c.columns===7?'active':''}">7個</button></div></div><div class="setting-choice"><strong>顯示行數</strong><div class="segmented"><button data-action="category-rows" data-value="1" class="${c.rows===1?'active':''}">1行</button><button data-action="category-rows" data-value="2" class="${c.rows===2?'active':''}">2行</button></div></div>${row('最後一行最後一格顯示搜尋','搜尋會佔用一格；超出分類仍可左右滑動',`<button class="toggle ${c.showSearch?'on':''}" data-action="toggle-category-search" aria-pressed="${c.showSearch?'true':'false'}"><i></i></button>`)}`)}${panel('六套品牌主題',`<div class="theme-grid">${[['warm','暖米'],['tea','焙茶'],['sprout','青芽'],['purple','紫米'],['sunset','夕照'],['mist','霧藍']].map(([id,name])=>`<button data-action="choose-theme" data-value="${id}" class="theme ${displaySettings.theme===id?'active':''}"><i class="${id}"></i>${name}</button>`).join('')}</div>${row('主題套用','所有子頁重新載入時讀取同一設定',tag('全局','ok'))}`)}</div>${panel('維護入口',row('退出全螢幕模式／進入維護','二次確認，不設密碼。','<button class="ghost-danger" data-action="open-confirm" data-value="exit">退出全螢幕模式</button>'))}`}
function diagnostic(){return buildDiagnosticReport({version:VERSION,terminalId,operations,printers:printerState,storageKeys:localStorage.length,updateSource:operations.updateSource||'',capabilities:{online:navigator.onLine,fullscreen:Boolean(document.fullscreenEnabled),fileImport:typeof FileReader!=='undefined'}})}
function systemContent(){const d=diagnostic();if(systemView==='audit')return `${note('操作紀錄只追加，不會用來改寫原訂單。')}<div class="audit-list">${[...(operations.audit||[])].reverse().map(e=>`<article><span><strong>${escapeHtml(e.type)}</strong><small>${dateTime(e.at)}｜${escapeHtml(e.terminalId||terminalId)}</small></span><pre>${escapeHtml(JSON.stringify(e.detail||{},null,2))}</pre></article>`).join('')||'<p>未有更多頁操作紀錄</p>'}</div>`;return `<div class="metrics">${metric('網頁核心',VERSION)}${metric('本機儲存鍵',String(d.storage.keys))}${metric('待同步',String(d.sync.pending))}${metric('打印失敗／阻塞',`${d.print.failed}／${d.print.blocked}`)}</div><div class="two-columns">${panel('裝置與同步',`${row('正式終端',terminalId)}${row('網絡狀態',navigator.onLine?'在線；本機仍是營運權威':'離線可營運')}${row('同步工作',`${d.sync.pending} 項待正式雲端接口`)}${row('安卓打印橋接',printerState.bridge.status==='connected'?'已連接':'尚未封裝 APK，工作保留待橋接',tag(printerState.bridge.status==='connected'?'可用':'待橋接',printerState.bridge.status==='connected'?'ok':'warn'))}<div class="button-row"><button data-action="retry-sync">重試同步工作</button><button data-action="download-diagnostic">下載診斷報告</button></div>`)}${panel('更新與稽核',`${row('更新來源',operations.updateSource||'未設定更新來源')}${row('最近檢查',dateTime(operations.updateChecks?.at(-1)?.at))}${note('未設定更新來源時，只保存檢查結果，唔會顯示已下載或已安裝。','small')}<div class="button-row"><button data-action="view-audit">查看操作紀錄</button><button class="primary" data-action="check-update">檢查更新</button></div>`)} </div>`}

