function confirmDialog(){const d=confirms[confirmId];if(!d)return '';return `<div class="dialog-layer confirm-layer"><div class="dialog-scrim" aria-hidden="true"></div><section class="confirm-dialog" role="alertdialog" aria-modal="true"><div class="confirm-body"><span>!</span><h2>${d.title}</h2><p>${d.copy}</p><div>${d.checks.map(x=>`<b><i>✓</i>${x}</b>`).join('')}</div></div><footer><button data-action="close-confirm">返回</button><button class="${['restore','exit'].includes(confirmId)?'danger':'primary'}" data-action="confirm-action" data-value="${confirmId}">${d.button}</button></footer></section></div>`}
function render(){app.innerHTML=mainPage()+detailDialog()+confirmDialog()+'<div id="toast" class="toast"></div>'}
function field(name){return app.querySelector(`[data-field="${name}"]`)}
function currentLocalValues(){const values={};for(let i=0;i<localStorage.length;i++){const key=localStorage.key(i);if(key?.startsWith('morefun:')&&key!==BACKUP_STORAGE_KEY)values[key]=localStorage.getItem(key)}return values}
function downloadText(filename,text,type='text/plain;charset=utf-8'){const blob=new Blob([text],{type}),url=URL.createObjectURL(blob),link=document.createElement('a');link.href=url;link.download=filename;document.body.append(link);link.click();link.remove();setTimeout(()=>URL.revokeObjectURL(url),1000)}
function createLocalBackup(reason='manual'){const envelope=createBackupEnvelope(currentLocalValues(),{terminalId,reason}),check=validateBackupEnvelope(envelope);if(!check.ok)throw new Error(check.errors.join('；'));backupState.latestEnvelope=envelope;backupState.items=[...(backupState.items||[]),{id:envelope.id,createdAt:envelope.manifest.createdAt,checksum:envelope.checksum,keyCount:envelope.manifest.keyCount,reason,valid:true}].slice(-40);saveBackups();audit('backup.created',{backupId:envelope.id,reason});return envelope}
function saveDayCloseDraft(){const current=operations.dayCloseDraft||{},breakdown=current.cashBreakdown||{},counted=totalCashBreakdown(breakdown),openingFloat=Number(field('opening-float')?.value??current.openingFloat??0),retained=Number(field('cash-retained')?.value??current.cashRetained??0),withdrawn=Number(field('cash-withdrawn')?.value??current.cashWithdrawn??Math.max(0,counted-retained));operations.dayCloseDraft={...current,businessDate:report().businessWindow.id,cashBreakdown:breakdown,cashCounted:counted,openingFloat,cashWithdrawn:withdrawn,cashRetained:retained,expenses:current.expenses||operations.expenses||[],reason:field('difference-reason')?.value.trim()??current.reason??'',approvedOverride:Boolean(current.approvedOverride),savedAt:Date.now(),terminalId};saveOperations()}
function addExpense(){const amount=Number(field('expense-amount')?.value||0);if(amount<=0)throw new Error('支出金額必須大於零');saveDayCloseDraft();operations.dayCloseDraft.expenses=[...(operations.dayCloseDraft.expenses||[]),{id:`EXP-${Date.now()}`,category:field('expense-category')?.value||'其他',amount,paymentMethod:'現金',note:field('expense-note')?.value.trim()||'',createdAt:Date.now(),terminalId}];saveOperations()}
function applyDisplay(){const savedOrder=readJSON(ORDER_STORAGE_KEY,{}),categoryLayout=normalizeCategoryLayout(displaySettings.categoryLayout);settings={...settings,morePage:{...(settings.morePage||{}),quickMode:displaySettings.quickMode,productImages:displaySettings.productImages,sounds:displaySettings.sounds,theme:displaySettings.theme},categoryLayout,cart:{...(settings.cart||{}),showImages:displaySettings.productImages},catalog:{...(settings.catalog||{}),showImages:displaySettings.productImages}};writeJSON(SETTINGS_STORAGE_KEY,settings);orderState={...savedOrder,quickMode:displaySettings.quickMode,settings:{...(savedOrder.settings||{}),categoryLayout,cart:{...(savedOrder.settings?.cart||{}),showImages:displaySettings.productImages},catalog:{...(savedOrder.settings?.catalog||{}),showImages:displaySettings.productImages}}};writeJSON(ORDER_STORAGE_KEY,orderState);document.documentElement.dataset.theme=displaySettings.theme;audit('display.settings_saved',{...displaySettings,categoryLayout})}
function savePrinterFromForm(id){const index=printerState.printers.findIndex(x=>x.id===id),current=printerState.printers[index];if(index<0)return;const purpose=field('printer-purpose').value,type=purpose==='label-backup'?'label':purpose,requestedTemplate=field('printer-template').value,template=printerState.templates.find(x=>x.id===requestedTemplate&&x.documentType===type)||printerState.templates.find(x=>x.documentType===type&&x.status==='published');if(!template)throw new Error('所選用途未有已發佈打印格式');const next={...current,name:field('printer-name').value.trim(),host:field('printer-host').value.trim(),port:Number(field('printer-port').value),paperWidth:Number(field('printer-paper').value),copies:Number(field('printer-copies').value),timeoutMs:Number(field('printer-timeout').value),purposes:[purpose],templateAssignments:{...current.templateAssignments,[type]:template.id}},check=validatePrinter(next);if(!check.ok)throw new Error(check.errors.join('；'));printerState.printers[index]=next;printerState.routes[type]=id;savePrinters();audit('printer.settings_saved',{printerId:id,host:next.host,port:next.port,purpose,templateId:template.id});editingPrinterId=''}
function queueTest(id){const p=printerState.printers.find(x=>x.id===id),type=(p.purposes||[]).find(x=>['receipt','production','packing','label'].includes(x))||'label',originalRoute=printerState.routes[type],temporary={...printerState,routes:{...printerState.routes,[type]:id}};printerState=createPrintJobs({...sampleOrder(),id:'TEST-'+Date.now(),source:'設備測試'},temporary,{documents:[type]});printerState.routes[type]=originalRoute;savePrinters();audit('print.test_job_created',{printerId:id,type,status:printerState.jobs.at(-1)?.status});printerView='jobs'}
function runPrinterDiagnostic(id){const index=printerState.printers.findIndex(x=>x.id===id),diagnostic=diagnosePrinterConfiguration(printerState.printers[index],{bridgeConnected:printerState.bridge.status==='connected'});printerState.printers[index]={...printerState.printers[index],lastDiagnostic:diagnostic};printerState.diagnostics=[...(printerState.diagnostics||[]),diagnostic].slice(-100);savePrinters();audit('printer.diagnostic_completed',{printerId:id,status:diagnostic.status,errors:diagnostic.errors});return diagnostic}
function confirmAction(type){if(type==='exit'){window.parent?.postMessage?.({type:'morefun:exit-fullscreen'},'*');audit('display.exit_fullscreen_requested');confirmId='';render();showToast('已送出退出全螢幕要求');return}if(type==='update'){operations.updateChecks=[...(operations.updateChecks||[]),{at:Date.now(),status:'not_configured',result:'未設定更新來源'}];audit('update.checked',{status:'not_configured'});confirmId='';render();showToast('已保存檢查結果：未設定更新來源');return}if(type==='dayclose'){saveDayCloseDraft();const backup=createLocalBackup('before_day_close'),draft=operations.dayCloseDraft,close=createDayClose({orders,terminalId,cashCounted:draft.cashCounted,cashBreakdown:draft.cashBreakdown,openingFloat:draft.openingFloat,cashWithdrawn:draft.cashWithdrawn,cashRetained:draft.cashRetained,expenses:draft.expenses,reason:draft.reason,approvedOverride:draft.approvedOverride,existing:operations.dayCloses,backupId:backup.id}),cleared=clearDraftsForDayClose(readJSON(DRAFT_STORAGE_KEY,[]),{terminalId});writeJSON(DRAFT_STORAGE_KEY,cleared.remaining);operations.dayCloses=[...(operations.dayCloses||[]),close];operations.voidedDrafts=[...(operations.voidedDrafts||[]),...cleared.voided];operations.dayCloseDraft=null;saveOperations();audit('day_close.saved',{id:close.id,version:close.version,voidedDrafts:cleared.voided.length,reviewRequired:close.reviewRequired});confirmId='';render();showToast(`已完成本機日結 V${close.version}`);return}if(type==='restore'){if(!importedBackup)throw new Error('未有已驗證備份檔案');createLocalBackup('before_restore');const current=currentLocalValues(),next=restoreBackupValues(current,importedBackup,restoreScope),rollback={...current};try{if(restoreScope==='all')Object.keys(current).filter(key=>key!==BACKUP_STORAGE_KEY&&!Object.hasOwn(importedBackup.values,key)).forEach(key=>localStorage.removeItem(key));Object.entries(next).forEach(([key,value])=>localStorage.setItem(key,value))}catch(error){Object.keys(currentLocalValues()).forEach(key=>localStorage.removeItem(key));Object.entries(rollback).forEach(([key,value])=>localStorage.setItem(key,value));throw error}audit('backup.restored',{backupId:importedBackup.id,scope:restoreScope});confirmId='';render();showToast('恢復完成；請重新載入核對資料')}}

function handle(button){const action=button.dataset.action,value=button.dataset.value,id=button.dataset.id;try{
  if(action==='shell-navigate'){if(button.dataset.route!=='more')navigate(button.dataset.route);return}
  if(action==='toggle-dayclose-approval'){saveDayCloseDraft();operations.dayCloseDraft.approvedOverride=!operations.dayCloseDraft.approvedOverride;saveOperations();render();return}
  if(action==='confirm-opening-cash'){const businessDate=report().businessWindow.id,previousRetained=openingCashState().previousRetained,adjustment=Number(field('opening-adjustment')?.value||0),openingCash=Math.max(0,previousRetained+adjustment),entry={businessDate,previousRetained,adjustment,openingCash,confirmedAt:Date.now(),terminalId};operations.openingCashAdjustments=[...(operations.openingCashAdjustments||[]).filter(row=>row.businessDate!==businessDate),entry];operations.dayCloseDraft={...(operations.dayCloseDraft||{}),businessDate,openingFloat:openingCash};saveOperations();audit('opening_cash.confirmed',entry);render();showToast(`今日開工現金已確認：${money(openingCash)}`);return}
  if(action==='navigate')navigate(value);else if(action==='open-detail'){detailId=value;systemView='summary';reportDrilldown=null;render()}else if(action==='close-detail'){detailId='';editingPrinterId='';previewTemplateId='';reportDrilldown=null;render()}else if(action==='report-range'){reportPreset=value;reportDrilldown=null;if(value!=='custom')reportRange=buildReportRange(value);render()}else if(action==='apply-custom-range'){reportCustomStart=app.querySelector('[data-report-start]')?.value||reportCustomStart;reportCustomEnd=app.querySelector('[data-report-end]')?.value||reportCustomEnd;reportRange=buildReportRange('custom',{startDate:reportCustomStart,endDate:reportCustomEnd});reportDrilldown=null;render();showToast(`已套用 ${reportRange.label}`)}else if(action==='report-tab'){reportTab=value;reportDrilldown=null;render()}else if(action==='report-product-view'){reportProductView=value;reportDrilldown=null;render()}else if(action==='report-drilldown'){reportDrilldown={kind:button.dataset.kind,index:Number(button.dataset.index)};render()}else if(action==='close-report-drilldown'){reportDrilldown=null;render()}else if(action==='export-report'){const selectedReport=analyticsReport();downloadText(`morefun-${selectedReport.range.id}-report.csv`,buildCsvExport(selectedReport,orders),'text/csv;charset=utf-8');audit('report.exported',{range:selectedReport.range});showToast('已建立目前日期範圍 CSV 報表')}else if(action==='save-dayclose-draft'){saveDayCloseDraft();render();showToast('日結草稿已保存')}else if(action==='add-expense'){addExpense();render();showToast('支出已加入日結草稿')}else if(action==='remove-expense'){saveDayCloseDraft();operations.dayCloseDraft.expenses.splice(Number(button.dataset.index),1);saveOperations();render()}else if(action==='toggle-setting'){displaySettings[value]=!displaySettings[value];render()}else if(action==='category-columns'){displaySettings.categoryLayout=normalizeCategoryLayout({...displaySettings.categoryLayout,columns:Number(value)});render()}else if(action==='category-rows'){displaySettings.categoryLayout=normalizeCategoryLayout({...displaySettings.categoryLayout,rows:Number(value)});render()}else if(action==='toggle-category-search'){displaySettings.categoryLayout={...displaySettings.categoryLayout,showSearch:!displaySettings.categoryLayout.showSearch};render()}else if(action==='choose-theme'){displaySettings.theme=value;render()}else if(action==='save-display'){applyDisplay();render();showToast('設定已保存並套用到全局')}else if(action==='printer-view'){printerView=value;editingPrinterId='';render()}else if(action==='open-print-jobs'){printerView='jobs';editingPrinterId='';render()}else if(action==='edit-printer'){editingPrinterId=id;render()}else if(action==='cancel-printer-edit'){editingPrinterId='';render()}else if(action==='save-printer'){savePrinterFromForm(id);render();showToast('設備設定已保存')}else if(action==='queue-test-print'){queueTest(id);render();showToast('測試工作已建立；等待安卓橋接實體輸出')}else if(action==='preview-template'){previewTemplateId=id;render()}else if(action==='close-template-preview'){previewTemplateId='';render()}else if(action==='retry-print-job'){const index=printerState.jobs.findIndex(x=>x.id===id),job=printerState.jobs[index],p=printerState.printers.find(x=>x.id===job.printerId),check=validatePrinter(p);if(!check.ok)throw new Error(check.errors.join('；'));printerState.jobs[index]=retryPrintJob(job);savePrinters();audit('print.job_retried',{jobId:id});render()}else if(action==='reroute-print-job'){if(!value){rerouteJobId=rerouteJobId===id?'':id;render()}else{const index=printerState.jobs.findIndex(x=>x.id===id),target=printerState.printers.find(x=>x.id===value);printerState.jobs[index]=reroutePrintJob(printerState.jobs[index],target);rerouteJobId='';savePrinters();audit('print.job_rerouted',{jobId:id,printerId:value});render();showToast('打印工作已改送')}}else if(action==='build-bridge-payload'){const job=printerState.jobs.find(x=>x.id===id),p=printerState.printers.find(x=>x.id===job.printerId);if(!job.document)throw new Error('舊工作未有完整格式內容，請重新建立或補印');const payload=buildAndroidPrintPayload(job,p,job.document);downloadText(`${job.id}-android-payload.json`,JSON.stringify(payload,null,2),'application/json');audit('print.bridge_payload_exported',{jobId:id});showToast('已建立安卓橋接資料；未有當作實體打印成功')}else if(action==='create-backup'){createLocalBackup('manual');render();showToast('安全快照已建立並通過校驗')}else if(action==='download-backup'){if(!backupState.latestEnvelope)throw new Error('尚未建立備份');downloadText(`${backupState.latestEnvelope.id}.json`,JSON.stringify(backupState.latestEnvelope,null,2),'application/json');audit('backup.downloaded',{backupId:backupState.latestEnvelope.id});showToast('已建立可下載備份檔')}else if(action==='restore-scope'){restoreScope=value;confirmId='restore';render()}else if(action==='download-diagnostic'){downloadText(`morefun-diagnostic-${Date.now()}.json`,JSON.stringify(diagnostic(),null,2),'application/json');audit('diagnostic.downloaded');showToast('診斷報告已建立')}else if(action==='view-audit'){systemView='audit';render()}else if(action==='retry-sync'){operations.outbox=(operations.outbox||[]).map(x=>({...x,status:'waiting_external_connector',attempts:Number(x.attempts||0)+1,lastAttemptAt:Date.now()}));audit('sync.retry_requested',{count:operations.outbox.length});render();showToast(operations.outbox.length?'已保存重試要求，等待正式同步接口':'未有待同步工作')}else if(action==='check-update'){confirmId='update';render()}else if(action==='open-confirm'){confirmId=value;render()}else if(action==='close-confirm'){confirmId='';render()}else if(action==='confirm-action')confirmAction(value)
}catch(error){render();showToast(error.message||'操作未完成，資料已保留')}}
function handleDayCloseInput(input){
  const action=input.dataset.action,fieldName=input.dataset.field;
  if(!action?.startsWith('denomination-')&&!['opening-float','cash-withdrawn','cash-retained'].includes(fieldName))return;
  const current=operations.dayCloseDraft||{businessDate:report().businessWindow.id,expenses:operations.expenses||[],cashBreakdown:{},approvedOverride:false};
  if(action?.startsWith('denomination-')){
    try{
      current.openingFloat=Number(current.openingFloat??field('opening-float')?.value??0);
      const source=action==='denomination-amount'?'amount':'quantity';
      current.cashBreakdown=syncCashDenomination(current.cashBreakdown||{},input.dataset.denomination,{source,value:input.value});
      input.setCustomValidity('');
      const row=current.cashBreakdown[input.dataset.denomination],other=app.querySelector(`[data-denomination="${input.dataset.denomination}"][data-action="${source==='amount'?'denomination-quantity':'denomination-amount'}"]`);
      if(other)other.value=source==='amount'?row.quantity:row.amount;
      current.cashCounted=totalCashBreakdown(current.cashBreakdown);
      if(!current.distributionTouched)Object.assign(current,defaultCashDistribution(current.cashCounted,current.openingFloat));
      const total=app.querySelector('[data-live="cash-counted"]'),hidden=field('cash-counted'),withdrawn=field('cash-withdrawn'),retained=field('cash-retained');
      if(total)total.textContent=money(current.cashCounted);if(hidden)hidden.value=current.cashCounted;if(withdrawn)withdrawn.value=current.cashWithdrawn;if(retained)retained.value=current.cashRetained;
    }catch(error){input.setCustomValidity(error.message);input.reportValidity();return}
  }else{
    const value=Math.max(0,Number(input.value||0));
    if(fieldName==='opening-float'){
      current.openingFloat=value;
      if(!current.distributionTouched)Object.assign(current,defaultCashDistribution(current.cashCounted,value));
      const withdrawn=field('cash-withdrawn'),retained=field('cash-retained');
      if(withdrawn)withdrawn.value=current.cashWithdrawn;if(retained)retained.value=current.cashRetained;
    }
    if(fieldName==='cash-withdrawn'){current.distributionTouched=true;current.cashWithdrawn=value;current.cashRetained=Math.max(0,Number(current.cashCounted||0)-value);const other=field('cash-retained');if(other)other.value=current.cashRetained}
    if(fieldName==='cash-retained'){current.distributionTouched=true;current.cashRetained=value;current.cashWithdrawn=Math.max(0,Number(current.cashCounted||0)-value);const other=field('cash-withdrawn');if(other)other.value=current.cashWithdrawn}
  }
  operations.dayCloseDraft={...current,savedAt:Date.now(),terminalId};saveOperations();
}
app.addEventListener('click',event=>{const button=event.target.closest('[data-action="run-printer-diagnostic"]');if(!button)return;event.stopImmediatePropagation();try{const result=runPrinterDiagnostic(button.dataset.id);render();showToast(result.status==='configuration_error'?result.errors.join('；'):result.nextStep)}catch(error){render();showToast(error.message||'診斷未完成')}});
app.addEventListener('click',event=>{const button=event.target.closest('[data-action="open-confirm"][data-value="dayclose"]');if(button)try{saveDayCloseDraft()}catch{}},true);
app.addEventListener('click',event=>{const button=event.target.closest('[data-action]');if(button&&button.type!=='file'&&!button.disabled)handle(button)});
app.addEventListener('input',event=>handleDayCloseInput(event.target));
app.addEventListener('input',event=>{if(event.target.dataset.field!=='opening-adjustment')return;const output=field('opening-cash'),previous=Number(field('previous-retained')?.value||0);if(output)output.value=Math.max(0,previous+Number(event.target.value||0))});
app.addEventListener('change',event=>{if(detailId==='dayclose'&&(event.target.dataset.action?.startsWith('denomination-')||['opening-float','cash-withdrawn','cash-retained'].includes(event.target.dataset.field))){saveDayCloseDraft();render()}});
app.addEventListener('change',event=>{const input=event.target.closest('[data-action="import-backup"]');if(!input?.files?.[0])return;const reader=new FileReader();reader.onload=()=>{try{const parsed=JSON.parse(String(reader.result||'')),check=validateBackupEnvelope(parsed);importedBackup=parsed;backupState.imported=parsed;saveBackups();audit('backup.imported',{backupId:parsed.id,valid:check.ok});render();showToast(check.ok?'備份檔校驗通過':'備份檔校驗失敗，禁止恢復')}catch{importedBackup=null;render();showToast('備份檔案格式不正確')}};reader.readAsText(input.files[0])});
render();
